; Function Attrs: nocallback nofree nosync nounwind willreturn memory(none)
declare <4 x float> @llvm.x86.sse.max.ps(<4 x float>, <4 x float>) #0

define <4 x float> @test_max_allow_negzero_first() {
; CHECK-LABEL: define <4 x float> @test_max_allow_negzero_first() {
; CHECK-NEXT:  [[ENTRY:.*:]]
; CHECK-NEXT:    ret <4 x float> splat (float 1.000000e+00)
entry:
  %r = call <4 x float> @llvm.x86.sse.max.ps(<4 x float> <float -0.000000e+00, float -0.000000e+00, float -0.000000e+00, float -0.000000e+00>, <4 x float> <float 1.000000e+00, float 1.000000e+00, float 1.000000e+00, float 1.000000e+00>)
  ret <4 x float> %r
}

